// Proxy GeoTIFF: valida URL, inyecta GOOGLE_API_KEY (server-side),
// descarga el binario, convierte a base64 y devuelve.
// Todo en un solo Code node para minimizar puntos de falla en n8n.

const src = $input.first().json;
const body = src.body || src;
const urlIn = body && body.url;

if (!urlIn || typeof urlIn !== 'string') {
  return [{ json: { ok: false, reason: 'invalid_input', detail: 'url requerida' } }];
}
if (!urlIn.startsWith('https://solar.googleapis.com/')) {
  return [{ json: { ok: false, reason: 'invalid_url', detail: 'url debe ser de solar.googleapis.com' } }];
}

// API key del entorno de n8n (Railway env var GOOGLE_API_KEY)
let gkey = null;
try { gkey = $env && $env.GOOGLE_API_KEY; } catch (_) { /* ignore */ }
if (!gkey) {
  return [{ json: { ok: false, reason: 'missing_env', detail: 'GOOGLE_API_KEY no configurada en n8n (Railway → Variables)' } }];
}

// Quita key existente (si la había) y agrega la actual — string manipulation
// pura, sin URL constructor (más robusto en sandbox de n8n).
const hashIdx = urlIn.indexOf('#');
const urlNoHash = hashIdx >= 0 ? urlIn.slice(0, hashIdx) : urlIn;
const qIdx = urlNoHash.indexOf('?');
const base = qIdx >= 0 ? urlNoHash.slice(0, qIdx) : urlNoHash;
const qs = qIdx >= 0 ? urlNoHash.slice(qIdx + 1) : '';
const params = qs.split('&').filter(p => p && p.split('=')[0] !== 'key');
params.push('key=' + encodeURIComponent(gkey));
const finalUrl = base + '?' + params.join('&');

// Descarga el binario usando helpers de n8n.
let response;
try {
  response = await this.helpers.httpRequest({
    method: 'GET',
    url: finalUrl,
    encoding: 'arraybuffer',
    returnFullResponse: true,
    timeout: 30000,
  });
} catch (err) {
  const code = err.response?.status || err.statusCode || err.httpCode || 'n/a';
  let bodyText = '';
  try {
    const b = err.response?.data || err.body;
    if (b) bodyText = (typeof b === 'string' ? b : Buffer.isBuffer(b) ? b.toString('utf8') : JSON.stringify(b)).slice(0, 400);
  } catch (_) {}
  return [{ json: { ok: false, reason: 'http_error', detail: 'Google ' + code + ': ' + (bodyText || err.message || 'sin cuerpo') } }];
}

const statusCode = response?.statusCode || response?.status;
if (statusCode && statusCode >= 400) {
  let bodyText = '';
  try { bodyText = Buffer.isBuffer(response.body) ? response.body.toString('utf8') : (typeof response.body === 'string' ? response.body : JSON.stringify(response.body)); } catch (_) {}
  return [{ json: { ok: false, reason: 'http_error', detail: 'Google ' + statusCode + ': ' + bodyText.slice(0, 400) } }];
}

const raw = response?.body;
if (!raw) {
  return [{ json: { ok: false, reason: 'empty_body', detail: 'Google devolvió respuesta vacía (status ' + (statusCode || 'n/a') + ')' } }];
}
const buf = Buffer.isBuffer(raw) ? raw : Buffer.from(raw);
const base64 = buf.toString('base64');
const mimeType = (response.headers && (response.headers['content-type'] || response.headers['Content-Type'])) || 'image/tiff';

return [{ json: { ok: true, base64, mimeType, size: buf.length } }];
